
(function() {
    class EmbeddedProject extends HTMLElement {
        constructor() {
            super();
            this.attachShadow({mode: 'open'});
        }

        connectedCallback() {
            const shadow = this.shadowRoot;
            const decodeB64 = (str) => {
                try {
                    return decodeURIComponent(escape(atob(str)));
                } catch (e) {
                    return atob(str);
                }
            };

            // 1. Inject External CSS
            [].forEach(href => {
                const link = document.createElement('link');
                link.rel = 'stylesheet';
                link.href = href;
                shadow.appendChild(link);
            });

            // 2. Inject Internal Styles
            const style = document.createElement('style');
            style.textContent = `:host { display: block; width: 100%; min-height: 100px; } .shadow-body { width: 100%; display: block; position: relative; } ` + decodeB64("");
            shadow.appendChild(style);
            
            // 3. Inject HTML
            const container = document.createElement('div');
            container.id = 'embedded-container';
            container.className = "shadow-body " + "";
            container.setAttribute('style', "");
            container.innerHTML = decodeB64("");
            shadow.appendChild(container);

            // 4. Load Scripts
            const extJs = [];
            const loadScripts = async () => {
                for (const src of extJs) {
                    await new Promise((resolve) => {
                        const s = document.createElement('script');
                        s.src = src;
                        s.onload = resolve;
                        s.onerror = resolve;
                        shadow.appendChild(s);
                    });
                }
                
                const jsCode = decodeB64("");
                if (jsCode.trim()) {
                    const isModule = jsCode.includes('import ') || jsCode.includes('export ');
                    const finalCode = isModule ? jsCode : "(function(shadowRoot){ " + jsCode + " })(this.shadowRoot);";
                    const blob = new Blob([finalCode], { type: 'text/javascript' });
                    const scriptURL = URL.createObjectURL(blob);
                    const script = document.createElement('script');
                    if (isModule) script.type = 'module';
                    script.src = scriptURL;
                    shadow.appendChild(script);
                }
            };
            loadScripts();
        }
    }

    if (!customElements.get('embedded-project')) {
        customElements.define('embedded-project', EmbeddedProject);
    }
})();
